"use client";

import { useState } from "react";
import { Copy, Check, User } from "lucide-react";
import type { Message } from "@/lib/api";

interface ChatMessageProps {
  message: Message;
  index: number;
}

/** Very simple markdown → HTML renderer (no external lib needed) */
function renderMarkdown(text: string): string {
  return text
    // Headings
    .replace(/^### (.+)$/gm, "<h3>$1</h3>")
    .replace(/^## (.+)$/gm, "<h2>$1</h2>")
    .replace(/^# (.+)$/gm, "<h1>$1</h1>")
    // Bold & italic
    .replace(/\*\*\*(.+?)\*\*\*/g, "<strong><em>$1</em></strong>")
    .replace(/\*\*(.+?)\*\*/g, "<strong>$1</strong>")
    .replace(/\*(.+?)\*/g, "<em>$1</em>")
    // Inline code
    .replace(/`([^`]+)`/g, "<code>$1</code>")
    // Code blocks
    .replace(/```[\w]*\n?([\s\S]*?)```/g, "<pre><code>$1</code></pre>")
    // Unordered lists
    .replace(/^\s*[-*•] (.+)$/gm, "<li>$1</li>")
    .replace(/(<li>.*<\/li>(\n|$))+/g, (match) => `<ul>${match}</ul>`)
    // Ordered lists
    .replace(/^\d+\. (.+)$/gm, "<li>$1</li>")
    // Blockquote
    .replace(/^> (.+)$/gm, "<blockquote>$1</blockquote>")
    // Line breaks → paragraphs
    .split(/\n\n+/)
    .map((block) => {
      if (
        block.startsWith("<h") ||
        block.startsWith("<ul") ||
        block.startsWith("<ol") ||
        block.startsWith("<pre") ||
        block.startsWith("<blockquote") ||
        block.startsWith("<li")
      ) {
        return block;
      }
      return `<p>${block.replace(/\n/g, "<br/>")}</p>`;
    })
    .join("\n");
}

export default function ChatMessage({ message, index }: ChatMessageProps) {
  const [copied, setCopied] = useState(false);
  const isUser = message.role === "user";

  const handleCopy = async () => {
    await navigator.clipboard.writeText(message.content);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <div
      className={`flex items-start gap-3 animate-fade-slide-up ${isUser ? "flex-row-reverse" : "flex-row"}`}
      style={{ animationDelay: `${Math.min(index * 0.03, 0.3)}s` }}
      id={`message-${index}`}
    >
      {/* Avatar */}
      <div
        style={{
          background: isUser ? "var(--accent)" : "var(--surface-2)",
          border: isUser ? "none" : "1px solid var(--border)",
          flexShrink: 0,
          boxShadow: isUser ? "0 0 12px var(--accent-glow)" : "none",
        }}
        className="w-8 h-8 rounded-full flex items-center justify-center text-sm"
      >
        {isUser ? <User size={15} color="#fff" /> : "🤖"}
      </div>

      {/* Content wrapper */}
      <div className={`flex flex-col gap-1 max-w-[80%] ${isUser ? "items-end" : "items-start"}`}>
        <div
          style={{
            background: isUser ? "var(--user-bubble)" : "var(--ai-bubble)",
            border: isUser ? "none" : "1px solid var(--border)",
            color: isUser ? "#fff" : "var(--foreground)",
            boxShadow: isUser ? "0 4px 20px var(--accent-glow)" : "none",
          }}
          className={`px-4 py-3 rounded-2xl text-sm leading-relaxed ${
            isUser ? "rounded-tr-sm" : "rounded-tl-sm"
          }`}
        >
          {isUser ? (
            <p style={{ whiteSpace: "pre-wrap" }}>{message.content}</p>
          ) : (
            <div
              className="prose-chat"
              dangerouslySetInnerHTML={{ __html: renderMarkdown(message.content) }}
            />
          )}
        </div>

        {/* Copy button — only for AI messages */}
        {!isUser && (
          <button
            id={`copy-btn-${index}`}
            onClick={handleCopy}
            style={{ color: "var(--muted)" }}
            className="flex items-center gap-1 text-xs px-2 py-1 rounded-md transition-all hover:opacity-70 cursor-pointer"
            aria-label="Copy response"
          >
            {copied ? (
              <>
                <Check size={12} />
                Copied
              </>
            ) : (
              <>
                <Copy size={12} />
                Copy
              </>
            )}
          </button>
        )}
      </div>
    </div>
  );
}
