"use client";

import { useRef, useEffect, KeyboardEvent, ChangeEvent } from "react";
import { Send, Sparkles } from "lucide-react";

interface ChatInputProps {
  value: string;
  onChange: (val: string) => void;
  onSubmit: () => void;
  isLoading: boolean;
}

export default function ChatInput({ value, onChange, onSubmit, isLoading }: ChatInputProps) {
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  /* Auto-resize textarea */
  useEffect(() => {
    const el = textareaRef.current;
    if (!el) return;
    el.style.height = "auto";
    el.style.height = `${Math.min(el.scrollHeight, 180)}px`;
  }, [value]);

  const handleKeyDown = (e: KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSubmit();
    }
  };

  const handleSubmit = () => {
    if (!value.trim() || isLoading) return;
    onSubmit();
  };

  const handleChange = (e: ChangeEvent<HTMLTextAreaElement>) => {
    onChange(e.target.value);
  };

  return (
    <div
      style={{
        background: "var(--surface)",
        borderTop: "1px solid var(--border)",
      }}
      className="sticky bottom-0 z-40 px-4 py-4"
    >
      <div className="max-w-3xl mx-auto">
        <div
          style={{
            background: "var(--surface-2)",
            border: "1px solid var(--border)",
            transition: "border-color 0.2s",
          }}
          className="flex items-end gap-3 rounded-2xl px-4 py-3 focus-within:border-[color:var(--accent)]"
          onFocus={(e) =>
            (e.currentTarget.style.borderColor = "var(--accent)")
          }
          onBlur={(e) =>
            (e.currentTarget.style.borderColor = "var(--border)")
          }
        >
          <Sparkles
            size={16}
            style={{ color: "var(--accent)", flexShrink: 0, marginBottom: 4 }}
          />

          <textarea
            id="chat-input"
            ref={textareaRef}
            value={value}
            onChange={handleChange}
            onKeyDown={handleKeyDown}
            disabled={isLoading}
            rows={1}
            placeholder="Ask anything — science, math, history, literature…"
            style={{
              background: "transparent",
              color: "var(--foreground)",
              resize: "none",
              outline: "none",
              border: "none",
              lineHeight: "1.6",
            }}
            className="flex-1 text-sm placeholder:text-[color:var(--muted)] disabled:opacity-50
                       scrollbar-hide overflow-y-auto"
          />

          <button
            id="send-btn"
            onClick={handleSubmit}
            disabled={!value.trim() || isLoading}
            aria-label="Send message"
            style={{
              background: value.trim() && !isLoading ? "var(--accent)" : "var(--surface)",
              border: "1px solid var(--border)",
              boxShadow: value.trim() && !isLoading ? "0 0 12px var(--accent-glow)" : "none",
              transition: "all 0.2s",
              flexShrink: 0,
            }}
            className="w-8 h-8 rounded-xl flex items-center justify-center cursor-pointer
                       disabled:opacity-40 disabled:cursor-not-allowed hover:opacity-80"
          >
            {isLoading ? (
              <span
                className="w-3.5 h-3.5 border-2 rounded-full animate-spin"
                style={{ borderColor: "var(--muted)", borderTopColor: "var(--accent)" }}
              />
            ) : (
              <Send size={14} color={value.trim() ? "#fff" : "var(--muted)"} />
            )}
          </button>
        </div>

        <p style={{ color: "var(--muted)" }} className="text-center text-[10px] mt-2">
          Press <kbd className="font-mono">Enter</kbd> to send · <kbd className="font-mono">Shift+Enter</kbd> for new line
        </p>
      </div>
    </div>
  );
}
