"use client";

import { useRef, useEffect } from "react";
import type { Message } from "@/lib/api";
import ChatMessage from "./ChatMessage";
import LoadingIndicator from "./LoadingIndicator";
import { GraduationCap, BookOpen } from "lucide-react";

interface ChatContainerProps {
  messages: Message[];
  isLoading: boolean;
  onSuggestion?: (text: string) => void;
}

const SUGGESTIONS = [
  "Explain Newton's laws of motion with examples",
  "Help me understand photosynthesis step by step",
  "What is the Pythagorean theorem and how do I use it?",
  "Summarize the causes of World War I",
  "How does the water cycle work?",
  "Explain the difference between mitosis and meiosis",
];

export default function ChatContainer({ messages, isLoading, onSuggestion }: ChatContainerProps) {
  const bottomRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [messages, isLoading]);

  const isEmpty = messages.length === 0 && !isLoading;

  return (
    <div
      id="chat-container"
      className="flex-1 overflow-y-auto"
      style={{ scrollbarWidth: "thin", scrollbarColor: "var(--scrollbar) transparent" }}
    >
      <div className="max-w-3xl mx-auto px-4 py-6 flex flex-col gap-4">
        {isEmpty ? (
          /* Welcome / empty state */
          <div className="flex flex-col items-center justify-center min-h-[60vh] gap-8">
            <div className="flex flex-col items-center gap-4 text-center">
              <div
                style={{
                  background: "linear-gradient(135deg, var(--accent) 0%, #8b5cf6 100%)",
                  boxShadow: "0 0 40px var(--accent-glow)",
                }}
                className="w-16 h-16 rounded-2xl flex items-center justify-center"
              >
                <GraduationCap size={30} color="#fff" />
              </div>
              <div>
                <h1
                  style={{ color: "var(--foreground)" }}
                  className="text-2xl font-bold tracking-tight"
                >
                  Welcome to StudyAI
                </h1>
                <p style={{ color: "var(--muted)" }} className="mt-1.5 text-sm max-w-xs">
                  Your intelligent study companion — ask anything, learn everything.
                </p>
              </div>
            </div>

            {/* Suggestion chips */}
            <div className="w-full max-w-xl">
              <div className="flex items-center gap-1.5 mb-3" style={{ color: "var(--muted)" }}>
                <BookOpen size={13} />
                <span className="text-xs">Try asking…</span>
              </div>
              <div className="grid grid-cols-1 sm:grid-cols-2 gap-2">
                {SUGGESTIONS.map((s) => (
                  <button
                    key={s}
                    onClick={() => onSuggestion?.(s)}
                    style={{
                      background: "var(--surface-2)",
                      border: "1px solid var(--border)",
                      color: "var(--foreground)",
                    }}
                    className="text-left text-xs px-3 py-2.5 rounded-xl transition-all hover:border-[color:var(--border-hover)] hover:opacity-80 cursor-pointer leading-relaxed"
                  >
                    {s}
                  </button>
                ))}
              </div>
            </div>
          </div>
        ) : (
          messages.map((msg, i) => (
            <ChatMessage key={i} message={msg} index={i} />
          ))
        )}

        {isLoading && <LoadingIndicator />}
        <div ref={bottomRef} />
      </div>
    </div>
  );
}
