"use client";

import { useState, useCallback, useEffect } from "react";
import Navbar from "@/components/Navbar";
import ChatContainer from "@/components/ChatContainer";
import ChatInput from "@/components/ChatInput";
import { askAI, loadHistory, saveHistory, clearHistory, type Message } from "@/lib/api";

export default function Home() {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [theme, setTheme] = useState<"dark" | "light">("dark");

  /* Load persisted chat + theme on mount */
  useEffect(() => {
    setMessages(loadHistory());
    const savedTheme = (localStorage.getItem("studyai_theme") as "dark" | "light") ?? "dark";
    setTheme(savedTheme);
    document.documentElement.setAttribute("data-theme", savedTheme);
  }, []);

  /* Persist messages whenever they change */
  useEffect(() => {
    if (messages.length > 0) saveHistory(messages);
  }, [messages]);

  const handleToggleTheme = useCallback(() => {
    setTheme((prev) => {
      const next = prev === "dark" ? "light" : "dark";
      document.documentElement.setAttribute("data-theme", next);
      localStorage.setItem("studyai_theme", next);
      return next;
    });
  }, []);

  const handleClearChat = useCallback(() => {
    setMessages([]);
    setError(null);
    clearHistory();
  }, []);

  const handleSubmit = useCallback(async () => {
    const question = input.trim();
    if (!question || isLoading) return;

    const userMsg: Message = { role: "user", content: question };
    const updatedHistory = [...messages, userMsg];

    setMessages(updatedHistory);
    setInput("");
    setIsLoading(true);
    setError(null);

    try {
      const { answer } = await askAI({ question, history: messages });
      setMessages([...updatedHistory, { role: "assistant", content: answer }]);
    } catch (err: unknown) {
      const msg = err instanceof Error ? err.message : "Something went wrong. Please try again.";
      setError(msg);
      /* Remove the user message if we get an API error so they can retry */
      setMessages(messages);
    } finally {
      setIsLoading(false);
    }
  }, [input, isLoading, messages]);

  const handleSuggestion = useCallback((text: string) => {
    setInput(text);
  }, []);

  return (
    <div
      style={{ background: "var(--background)", height: "100dvh" }}
      className="flex flex-col overflow-hidden"
      data-theme={theme}
    >
      <Navbar theme={theme} onToggleTheme={handleToggleTheme} onClearChat={handleClearChat} />

      <ChatContainer
        messages={messages}
        isLoading={isLoading}
        onSuggestion={handleSuggestion}
      />

      {/* Error banner */}
      {error && (
        <div
          style={{
            background: "#ff4d6d22",
            border: "1px solid #ff4d6d55",
            color: "#ff4d6d",
          }}
          className="mx-auto max-w-3xl w-full px-4 mb-2 py-2.5 rounded-xl text-xs flex items-center justify-between"
        >
          <span>⚠️ {error}</span>
          <button
            onClick={() => setError(null)}
            className="ml-4 opacity-70 hover:opacity-100 cursor-pointer"
          >
            ✕
          </button>
        </div>
      )}

      <ChatInput
        value={input}
        onChange={setInput}
        onSubmit={handleSubmit}
        isLoading={isLoading}
      />
    </div>
  );
}
